INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('tos programáticos em matéria dos comportamentos aditivos e das dependências, em particular do Plano Nacional para a Redução dos Comportamentos Aditivos e das Dependências e dos respetivos planos de ação plurianuais, para posterior apresentação ao Conselho Interministerial;
